import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSVulnerableServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Vulnerable code: User input is directly embedded into the HTML response without sanitization
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Vulnerable Page</title></head>");
        out.println("<body>");
        out.println("<h1>User Input: " + userInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }
}

